#!/usr/bin/env node
// Build n8n workflows for each test case using `claude -p` driving an MCP
// server, then write a manifest the eval CLI's --prebuilt-workflows flag
// accepts. Validates the produced manifest against the same Zod schema the
// loader uses, so shape regressions surface here rather than at eval time.

import { execSync, spawn } from 'child_process';
import { existsSync, mkdirSync, readFileSync, readdirSync, unlinkSync, writeFileSync } from 'fs';
import { homedir, tmpdir } from 'os';
import { basename, join, resolve } from 'path';
import { z } from 'zod';

import { ConversationTurnSchema, DEFAULT_DATASETS } from '../data/workflows/schema';
import { createLogger } from '../harness/logger';
import { prebuiltManifestSchema, type PrebuiltManifest } from '../harness/prebuilt-workflows';
import { runWithConcurrency } from '../harness/runner';
import { loadTestCasesFromLangTracer } from '../langtracer/provider';

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

interface CliArgs {
	iterations: number;
	concurrency: number;
	outputDir: string;
	manifestPath: string;
	statsPath: string;
	logDir: string;
	mcpServerName: string;
	builder: string;
	model: string;
	append: boolean;
	slugs: string[];
	maxAttempts: number;
	mcpTimeoutMs: number;
	/** When set, only build slugs whose `datasets` array includes this tier (mirrors eval --tier). */
	tier?: string;
	/** When set, instructs the model to pass `projectId` to
	 *  `create_workflow_from_code` so workflows land in a specific n8n project.
	 *  When unset, workflows go to the user's personal project (MCP default). */
	projectId?: string;
	/** Override the test-case JSON directory. Defaults to the n8n repo's
	 *  evaluations/data/workflows/, derived via `git rev-parse`. Setting this
	 *  lets the script run from outside the n8n repo. */
	workflowDir?: string;
	/** Working directory for the build subprocess. Lets the user spawn the
	 *  builder from a project where they have skills/settings configured,
	 *  independent of where the script itself runs. */
	buildCwd?: string;
	/** Test-case source: `disk` (default, from --workflow-dir) or `langtracer` (a suite over MCP). */
	source: 'disk' | 'langtracer';
	/** lang-tracer suite slug when `--source langtracer`. */
	suite?: string;
}

const HELP = `
Build n8n workflows for each test case using \`claude -p\` driving an MCP
server, write a manifest the eval CLI's --prebuilt-workflows flag accepts,
plus a build-stats sidecar with per-cohort cost/turn/duration aggregates.

Prerequisites:
  * \`claude\` CLI installed (https://docs.claude.com/claude-code)
  * ~/.claude.json has the MCP server block configured (project-scoped
    under .projects[<repo-root>].mcpServers[<name>] or globally under
    .mcpServers[<name>]). Default name: "n8n-mcp (instance)" — override
    with --mcp-server.
  * n8n instance reachable at the URL the MCP block points at.

Usage:
  pnpm eval:build-mcp-manifest [flags] [slug ...]

Flags:
  -n, --iterations N      Builds per slug (default: 1).
  -j, --concurrency N     Parallel builds (default: 1).
  --append                Append to existing manifest instead of overwriting.
  --output-dir DIR        Where manifest + logs go (default: cwd).
  --manifest PATH         Override manifest path (default: <output-dir>/manifest.json).
  --log-dir DIR           Override log dir (default: <output-dir>/logs).
  --mcp-server NAME       MCP server name in ~/.claude.json (default: "n8n-mcp (instance)").
  --builder LABEL         Free-form label written into manifest-stats.json
                          (default: "instance-mcp").
  --model MODEL           Anthropic model id passed to claude -p
                          (default: claude-sonnet-4-6).
  --max-attempts N        Retries per build when WORKFLOW_ID is missing (default: 3).
  --mcp-timeout-ms N      MCP_TIMEOUT env passed to claude -p (default: 120000).
  --project-id ID         n8n project to create the workflows in. Defaults
                          to the user's personal project.
  --source SRC            Test-case source: disk (default) or langtracer.
  --suite SLUG            lang-tracer suite slug (required with --source langtracer).
  --tier TIER             Only build test cases whose datasets array includes
                          TIER (e.g. "mcp"). Mirrors eval:instance-ai --tier.
                          Applies to discovered and positional slugs alike.
  --workflow-dir DIR      Test-case JSON directory. Defaults to
                          evaluations/data/workflows/ derived from the n8n
                          repo (via git). Set this to run from outside the
                          n8n repo.
  --build-cwd DIR         Working directory for the build subprocess.
                          Defaults to the n8n repo root when running inside
                          it, otherwise process.cwd(). Set this to spawn
                          the builder from a project where you have skills /
                          settings configured.
  -h, --help              Show this help.

Positional args:
  slug ...                Test case slugs to build (filenames in
                          evaluations/data/workflows/ without .json).
                          If omitted, every slug in that directory is built.
`;

interface ParseResult {
	helpRequested: boolean;
	args?: CliArgs;
}

function parseArgs(argv: string[]): ParseResult {
	const result: CliArgs = {
		iterations: 1,
		concurrency: 1,
		outputDir: process.cwd(),
		manifestPath: '',
		statsPath: '',
		logDir: '',
		mcpServerName: 'n8n-mcp (instance)',
		builder: 'instance-mcp',
		model: 'claude-sonnet-4-6',
		append: false,
		slugs: [],
		maxAttempts: 3,
		mcpTimeoutMs: 120_000,
		source: 'disk',
	};

	let i = 0;
	while (i < argv.length) {
		const arg = argv[i];
		switch (arg) {
			case '-n':
			case '--iterations':
				result.iterations = parseIntArg(argv, i, arg);
				i += 2;
				break;
			case '-j':
			case '--concurrency':
				result.concurrency = parseIntArg(argv, i, arg);
				i += 2;
				break;
			case '--append':
				result.append = true;
				i += 1;
				break;
			case '--output-dir':
				result.outputDir = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--manifest':
				result.manifestPath = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--log-dir':
				result.logDir = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--mcp-server':
				result.mcpServerName = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--builder':
				result.builder = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--model':
				result.model = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--max-attempts':
				result.maxAttempts = parseIntArg(argv, i, arg);
				i += 2;
				break;
			case '--mcp-timeout-ms':
				result.mcpTimeoutMs = parseIntArg(argv, i, arg);
				i += 2;
				break;
			case '--project-id':
				result.projectId = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--tier':
				result.tier = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--workflow-dir':
				result.workflowDir = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--build-cwd':
				result.buildCwd = nextArg(argv, i, arg);
				i += 2;
				break;
			case '--source': {
				const value = nextArg(argv, i, arg);
				if (value !== 'disk' && value !== 'langtracer') {
					throw new Error('--source must be "disk" or "langtracer"');
				}
				result.source = value;
				i += 2;
				break;
			}
			case '--suite':
				result.suite = nextArg(argv, i, arg);
				i += 2;
				break;
			case '-h':
			case '--help':
				return { helpRequested: true };
			default:
				if (arg.startsWith('--')) {
					throw new Error(`Unknown flag: ${arg.split('=', 1)[0]} (use --help)`);
				}
				result.slugs.push(arg);
				i += 1;
				break;
		}
	}

	if (result.iterations < 1) throw new Error('--iterations must be >= 1');
	if (result.concurrency < 1) throw new Error('--concurrency must be >= 1');
	if (result.maxAttempts < 1) throw new Error('--max-attempts must be >= 1');
	if (result.source === 'langtracer' && !result.suite) {
		throw new Error('--source langtracer requires --suite <slug>');
	}

	mkdirSync(result.outputDir, { recursive: true });
	if (!result.manifestPath) result.manifestPath = join(result.outputDir, 'manifest.json');
	if (!result.logDir) result.logDir = join(result.outputDir, 'logs');
	const base = result.manifestPath.replace(/\.json$/, '');
	result.statsPath = `${base}-stats.json`;
	mkdirSync(result.logDir, { recursive: true });

	return { helpRequested: false, args: result };
}

function readJson(path: string, label: string): unknown {
	const content = readFileSync(path, 'utf-8');
	try {
		return JSON.parse(content);
	} catch (error) {
		const msg = error instanceof Error ? error.message : String(error);
		throw new Error(`Failed to parse ${label} at ${path}: ${msg}`);
	}
}

function nextArg(argv: string[], i: number, flag: string): string {
	const value = argv[i + 1];
	if (value === undefined || value.startsWith('--')) {
		throw new Error(`Missing value for ${flag}`);
	}
	return value;
}

function parseIntArg(argv: string[], i: number, flag: string): number {
	const raw = nextArg(argv, i, flag);
	const parsed = parseInt(raw, 10);
	if (Number.isNaN(parsed)) throw new Error(`Invalid integer for ${flag}`);
	return parsed;
}

// ---------------------------------------------------------------------------
// MCP config — extract the named server block from ~/.claude.json
// ---------------------------------------------------------------------------

const claudeConfigSchema = z.object({
	mcpServers: z.record(z.unknown()).optional(),
	projects: z
		.record(z.object({ mcpServers: z.record(z.unknown()).optional() }).passthrough())
		.optional(),
});

function uniqueProjectScopes(scopes: Array<string | undefined>): string[] {
	const uniqueScopes: string[] = [];
	for (const scope of scopes) {
		if (!scope || uniqueScopes.includes(scope)) continue;
		uniqueScopes.push(scope);
	}
	return uniqueScopes;
}

function stageMcpConfig(serverName: string, projectScopes: readonly string[]): string {
	const claudeConfigPath = join(homedir(), '.claude.json');
	if (!existsSync(claudeConfigPath)) {
		throw new Error(`${claudeConfigPath} not found`);
	}
	const parsed = claudeConfigSchema.parse(readJson(claudeConfigPath, 'Claude Code config'));

	const projectScopedBlock = projectScopes
		.map((scope) => parsed.projects?.[scope]?.mcpServers?.[serverName])
		.find((block) => block !== undefined);
	const block = projectScopedBlock ?? parsed.mcpServers?.[serverName];
	if (block === undefined) {
		const scope = projectScopes.length
			? `project-scope under ${projectScopes.map((projectScope) => `"${projectScope}"`).join(', ')} or global`
			: 'global (no project scopes)';
		throw new Error(`MCP server "${serverName}" not configured in ${claudeConfigPath} (${scope})`);
	}

	const tmpPath = join(tmpdir(), `n8n-mcp-config-${process.pid}-${Date.now()}.json`);
	writeFileSync(tmpPath, JSON.stringify({ mcpServers: { [serverName]: block } }), {
		mode: 0o600,
	});
	return tmpPath;
}

/** Each non-alphanumeric character (excluding hyphen) becomes "_". Mirrors
 *  Claude Code's tool-prefix sanitization: "n8n-mcp (instance)" maps to
 *  "n8n-mcp__instance_", and the full prefix becomes "mcp__n8n-mcp__instance___". */
function sanitizeServerName(name: string): string {
	return name.replace(/[^a-zA-Z0-9-]/g, '_');
}

function buildAllowedTools(serverName: string): readonly string[] {
	return [`mcp__${sanitizeServerName(serverName)}`];
}

// ---------------------------------------------------------------------------
// `claude -p` subprocess invocation
// ---------------------------------------------------------------------------

const claudeSessionSchema = z
	.object({
		result: z.string().optional(),
		num_turns: z.number().optional(),
		total_cost_usd: z.number().optional(),
		duration_ms: z.number().optional(),
		subtype: z.string().optional(),
	})
	.passthrough();
type ClaudeSession = z.infer<typeof claudeSessionSchema>;

interface BuildAttempt {
	session: ClaudeSession | undefined;
	logFile: string;
}

async function runClaude(
	userMessage: string,
	args: CliArgs,
	mcpConfigPath: string,
	allowedTools: readonly string[],
	logFile: string,
): Promise<BuildAttempt> {
	return await new Promise((resolve) => {
		const claudeArgs = [
			'-p',
			userMessage,
			'--model',
			args.model,
			'--mcp-config',
			mcpConfigPath,
			'--strict-mcp-config',
			'--allowedTools',
			...allowedTools,
			'--output-format',
			'json',
		];
		const child = spawn('claude', claudeArgs, {
			env: { ...process.env, MCP_TIMEOUT: String(args.mcpTimeoutMs) },
			stdio: ['ignore', 'pipe', 'pipe'],
			cwd: args.buildCwd,
		});
		let stdout = '';
		let stderr = '';
		child.stdout.on('data', (chunk: Buffer) => {
			stdout += chunk.toString();
		});
		child.stderr.on('data', (chunk: Buffer) => {
			stderr += chunk.toString();
		});
		child.on('close', () => {
			// Persist stdout (or stderr fallback) for forensics regardless of parse success.
			writeFileSync(logFile, stdout || stderr || '{}');
			let session: ClaudeSession | undefined;
			try {
				const parsed = claudeSessionSchema.safeParse(JSON.parse(stdout));
				if (parsed.success) session = parsed.data;
			} catch {
				// stdout wasn't JSON — caller treats undefined session as failure.
			}
			resolve({ session, logFile });
		});
		child.on('error', () => {
			resolve({ session: undefined, logFile });
		});
	});
}

interface BuildOutcome {
	slug: string;
	iteration: number;
	workflowId: string | null;
	cost: number;
	turns: number;
	durationMs: number;
}

/** Canonical conversation-turn type (role enum + normalized text), reused from
 *  the harness schema instead of a looser inline `{ role: string; text }`. */
type ConversationTurn = z.infer<typeof ConversationTurnSchema>;

const testCaseSchema = z
	.object({
		// Reuse the canonical turn schema so `role` is the exact 'user' | 'assistant'
		// enum and the array (multi-line) `text` form is normalized as in the harness.
		conversation: z.array(ConversationTurnSchema).min(1),
	})
	.passthrough();

function buildPromptFromConversation(
	conversation: z.infer<typeof testCaseSchema>['conversation'],
): string {
	const [firstUserTurn, ...remainingUserTurns] = conversation
		.filter((turn) => turn.role === 'user')
		.map((turn) => turn.text.trim())
		.filter((text) => text.length > 0);

	if (!firstUserTurn) return conversation[0].text;
	if (remainingUserTurns.length === 0) return firstUserTurn;

	return [
		firstUserTurn,
		'Additional details from the user:',
		...remainingUserTurns.map((turn, index) => `${String(index + 1)}. ${turn}`),
		'',
		"Use all details above as requirements. Configure all nodes as completely as possible and don't ask me for credentials; I'll set them up later.",
	].join('\n\n');
}

function tailWorkflowId(text: string): string | null {
	const matches = [...text.matchAll(/WORKFLOW_ID=([A-Za-z0-9_-]+)/g)];
	return matches.length > 0 ? matches[matches.length - 1][1] : null;
}

async function buildOne(
	slug: string,
	iteration: number,
	args: CliArgs,
	mcpConfigPath: string,
	conversation: ConversationTurn[],
	allowedTools: readonly string[],
): Promise<BuildOutcome> {
	const projectInstruction = args.projectId
		? `\n\nWhen calling create_workflow_from_code, pass projectId: '${args.projectId}' so the workflow is created in that n8n project.`
		: '';

	const userMessage = `${buildPromptFromConversation(conversation)}${projectInstruction}

---
After you have created the workflow with create_workflow_from_code, print a final line of the exact form:

WORKFLOW_ID=<id>

where <id> is the workflowId returned by create_workflow_from_code. Emit it verbatim, no quotes, no markdown.`;

	let workflowId: string | null = null;
	let lastSession: ClaudeSession | undefined;
	for (let attempt = 1; attempt <= args.maxAttempts; attempt++) {
		const ts = new Date().toISOString().replace(/[:.]/g, '-');
		const logFile = join(args.logDir, `${slug}-iter${iteration}-attempt${attempt}-${ts}.json`);
		const { session } = await runClaude(userMessage, args, mcpConfigPath, allowedTools, logFile);
		lastSession = session;
		const id = session?.result ? tailWorkflowId(session.result) : null;
		if (id) {
			workflowId = id;
			break;
		}
		const reason = session?.subtype ?? 'no-stdout';
		console.log(
			`  [${slug}#${iteration}] attempt ${attempt}: no WORKFLOW_ID (${reason}, log: ${logFile})`,
		);
	}

	if (!workflowId) {
		console.log(`  [${slug}#${iteration}] FAILED after ${args.maxAttempts} attempts`);
	} else {
		console.log(`  [${slug}#${iteration}] ok → ${workflowId}`);
	}

	return {
		slug,
		iteration,
		workflowId,
		cost: lastSession?.total_cost_usd ?? 0,
		turns: lastSession?.num_turns ?? 0,
		durationMs: lastSession?.duration_ms ?? 0,
	};
}

// ---------------------------------------------------------------------------
// Manifest + stats output
// ---------------------------------------------------------------------------

function readExistingWorkflows(manifestPath: string): Record<string, string[]> {
	if (!existsSync(manifestPath)) return {};
	// The file exists — it must be parseable. Silently treating a malformed
	// manifest as empty would clobber accumulated entries on the next write
	// (especially destructive with --append, where the entire prior corpus
	// could be lost). Force the user to fix or remove the file first.
	try {
		return { ...prebuiltManifestSchema.parse(readJson(manifestPath, 'existing manifest')) };
	} catch (error) {
		const msg = error instanceof Error ? error.message : String(error);
		throw new Error(
			`Existing manifest at ${manifestPath} is malformed; remove or fix it before re-running:\n  ${msg}`,
		);
	}
}

function writeManifest(args: CliArgs, results: BuildOutcome[]): void {
	const workflows = readExistingWorkflows(args.manifestPath);

	if (!args.append) {
		// Without --append, clear entries for slugs we just rebuilt; preserve
		// other slugs in the existing manifest.
		for (const slug of new Set(results.map((r) => r.slug))) {
			delete workflows[slug];
		}
	}

	for (const r of results) {
		if (!r.workflowId) continue;
		if (!workflows[r.slug]) workflows[r.slug] = [];
		workflows[r.slug].push(r.workflowId);
	}

	const manifest: PrebuiltManifest = prebuiltManifestSchema.parse(workflows);

	writeFileSync(args.manifestPath, JSON.stringify(manifest, null, 2));
}

function writeStats(args: CliArgs, results: BuildOutcome[]): void {
	const successful = results.filter((r) => r.workflowId !== null);
	const total = successful.length;
	const sum = (selector: (r: BuildOutcome) => number) =>
		successful.reduce((s, r) => s + selector(r), 0);

	const stats = {
		version: 1 as const,
		builder: args.builder,
		summary: {
			totalBuilds: total,
			avgTurns: total > 0 ? sum((r) => r.turns) / total : 0,
			avgCostUSD: total > 0 ? sum((r) => r.cost) / total : 0,
			totalCostUSD: sum((r) => r.cost),
			avgDurationMs: total > 0 ? sum((r) => r.durationMs) / total : 0,
		},
		builds: successful.map((r) => ({
			slug: r.slug,
			iteration: r.iteration,
			workflowId: r.workflowId,
			turns: r.turns,
			costUSD: r.cost,
			durationMs: r.durationMs,
		})),
	};

	writeFileSync(args.statsPath, JSON.stringify(stats, null, 2));
}

function discoverSlugs(workflowDir: string): string[] {
	if (!existsSync(workflowDir)) {
		throw new Error(`Workflow directory not found: ${workflowDir}`);
	}
	return readdirSync(workflowDir)
		.filter((f) => f.endsWith('.json'))
		.map((f) => basename(f, '.json'))
		.sort();
}

const tierDatasetsSchema = z.object({ datasets: z.array(z.string()).optional() }).passthrough();

/** A test case's `datasets`, defaulting to the shared eval default when absent — mirrors the loader schema. */
function readDatasets(workflowDir: string, slug: string): string[] {
	const file = join(workflowDir, `${slug}.json`);
	if (!existsSync(file)) return [];
	try {
		return (
			tierDatasetsSchema.parse(readJson(file, `test case ${slug}`)).datasets ?? DEFAULT_DATASETS
		);
	} catch {
		return DEFAULT_DATASETS;
	}
}

/** Keep only slugs whose `datasets` includes `tier`, mirroring eval:instance-ai --tier semantics. */
function filterSlugsByTier(workflowDir: string, slugs: string[], tier: string): string[] {
	return slugs.filter((slug) => readDatasets(workflowDir, slug).includes(tier));
}

async function main(): Promise<void> {
	const parsed = parseArgs(process.argv.slice(2));
	if (parsed.helpRequested) {
		process.stdout.write(HELP);
		return;
	}
	const args = parsed.args!;

	try {
		execSync('command -v claude', { stdio: 'ignore' });
	} catch {
		throw new Error('claude not on PATH');
	}

	// Repo root scopes the staged MCP config (cwd fallback). Best-effort: the disk
	// source resolves/validates its own test-case dir below; langtracer pulls cases
	// over MCP, so it needs no repo at all and can run outside the n8n checkout.
	let repoRoot: string | undefined;
	try {
		repoRoot = execSync('git rev-parse --show-toplevel', { stdio: ['ignore', 'pipe', 'ignore'] })
			.toString()
			.trim();
	} catch {
		repoRoot = undefined;
	}

	if (args.buildCwd && !existsSync(args.buildCwd)) {
		throw new Error(`--build-cwd directory does not exist: ${args.buildCwd}`);
	}

	// Resolve slug -> conversation from the chosen source. Disk reads --workflow-dir
	// (positional slugs or discovered), langtracer pulls a suite over MCP; both feed
	// the same buildOne prompt.
	const casesBySlug = new Map<string, ConversationTurn[]>();
	if (args.source === 'langtracer') {
		const suite = args.suite;
		if (!suite) throw new Error('--source langtracer requires --suite <slug>');
		const cases = await loadTestCasesFromLangTracer({
			suite,
			tier: args.tier,
			logger: createLogger(false),
		});
		for (const { fileSlug, testCase } of cases)
			casesBySlug.set(fileSlug, testCase.conversation ?? []);
		if (args.slugs.length > 0) {
			const requested = new Set(args.slugs);
			for (const slug of [...casesBySlug.keys()]) {
				if (!requested.has(slug)) casesBySlug.delete(slug);
			}
		}
	} else {
		const workflowDir =
			args.workflowDir ??
			(repoRoot
				? join(repoRoot, 'packages/@n8n/instance-ai/evaluations/data/workflows')
				: undefined);
		if (!workflowDir) {
			throw new Error(
				'Disk source needs the n8n repo (run from inside it) or --workflow-dir; or use --source langtracer.',
			);
		}
		let slugs = args.slugs.length > 0 ? args.slugs : discoverSlugs(workflowDir);
		if (args.tier) slugs = filterSlugsByTier(workflowDir, slugs, args.tier);
		for (const slug of slugs) {
			const file = join(workflowDir, `${slug}.json`);
			if (!existsSync(file)) {
				console.log(`  [${slug}] skip: scenario file missing`);
				continue;
			}
			casesBySlug.set(slug, testCaseSchema.parse(readJson(file, `test case ${slug}`)).conversation);
		}
	}
	// Drop cases with no user turn to build from (e.g. seedThread-only).
	for (const [slug, conv] of [...casesBySlug]) {
		if (!conv.some((t) => t.role === 'user' && t.text.trim().length > 0)) {
			console.log(`  [${slug}] skip: no user turn to build from`);
			casesBySlug.delete(slug);
		}
	}
	args.slugs = [...casesBySlug.keys()];
	if (args.slugs.length === 0) {
		throw new Error(
			args.tier ? `No scenarios match --tier "${args.tier}"` : 'No scenarios to build',
		);
	}

	const projectScopes = uniqueProjectScopes([
		args.buildCwd ? resolve(args.buildCwd) : undefined,
		repoRoot,
		repoRoot ? undefined : process.cwd(),
	]);
	const mcpConfigPath = stageMcpConfig(args.mcpServerName, projectScopes);
	process.on('exit', () => {
		try {
			unlinkSync(mcpConfigPath);
		} catch {
			// best-effort
		}
	});

	const allowedTools = buildAllowedTools(args.mcpServerName);
	const tasks: Array<{ slug: string; iteration: number }> = [];
	for (const slug of args.slugs) {
		for (let i = 1; i <= args.iterations; i++) {
			tasks.push({ slug, iteration: i });
		}
	}

	console.log(
		`Building ${String(args.slugs.length)} scenario(s) × ${String(args.iterations)} iteration(s) = ${String(tasks.length)} workflow(s)`,
	);
	console.log(`MCP server:  ${args.mcpServerName}`);
	console.log(`Builder tag: ${args.builder}`);
	console.log(`Model:       ${args.model}`);
	console.log(`Concurrency: ${String(args.concurrency)}`);
	console.log(`Logs:        ${args.logDir}`);
	console.log(`Manifest:    ${args.manifestPath}`);
	console.log();

	const results = await runWithConcurrency(
		tasks,
		async (task) =>
			await buildOne(
				task.slug,
				task.iteration,
				args,
				mcpConfigPath,
				casesBySlug.get(task.slug) ?? [],
				allowedTools,
			),
		args.concurrency,
	);

	writeManifest(args, results);
	writeStats(args, results);

	console.log();
	console.log(`Manifest: ${args.manifestPath}`);
	console.log(`Stats:    ${args.statsPath}`);
	console.log(readFileSync(args.manifestPath, 'utf-8'));
}

main().catch((error: unknown) => {
	console.error(error instanceof Error ? error.message : error);
	process.exit(1);
});

import { z } from 'zod';

import { SUPPORTED_CREDENTIAL_TYPES } from '../../credentials/seeder';

/** Default `datasets` grouping for a case that omits the field — the single
 *  source of truth shared by the loader schema and the mcp-manifest tier reader. */
export const DEFAULT_DATASETS = ['full'];

/** A conversation turn's `text`: a string, or an array of lines joined with
 *  newlines. The array form lets long stage directions be authored readably
 *  (one line per element) in the JSON file; every consumer still receives a
 *  single string. Exported as the single source of truth so non-harness readers
 *  (e.g. the mcp-manifest builder) normalize identically. */
export const conversationTurnTextSchema = z
	.union([z.string(), z.array(z.string())])
	.transform((t) => (Array.isArray(t) ? t.join('\n') : t));

export const ConversationTurnSchema = z.object({
	role: z.enum(['user', 'assistant']),
	text: conversationTurnTextSchema,
});

const ExecutionScenarioSchema = z.object({
	name: z.string().min(1),
	description: z.string(),
	dataSetup: z.string(),
	successCriteria: z.string(),
	requires: z.string().optional(),
});

const workflowTestCaseObjectSchema = z
	.object({
		/** Optional human-readable note on what this case is testing (esp. for behaviour cases). */
		description: z.string().optional(),
		// Optional only because `seedThread` derives the live turn from the trace;
		// a refine() below requires it for every other case.
		conversation: z.array(ConversationTurnSchema).min(1).optional(),
		complexity: z.enum(['simple', 'medium', 'complex']),
		tags: z.array(z.string()),
		triggerType: z.enum(['manual', 'webhook', 'schedule', 'form']).optional(),
		executionScenarios: z.array(ExecutionScenarioSchema).min(1),
		messageBudget: z.number().int().positive().optional(),
		/** Optional NL assertions about the build CONVERSATION (process: clarifications, push-back,
		 *  ordering). LLM-judged from the transcript, so skipped in prebuilt/MCP runs. Counted as units. */
		processExpectations: z.array(z.string().min(1)).optional(),
		/** Optional NL assertions about the resulting WORKFLOW (outcome). LLM-judged from the workflow,
		 *  so they also run in prebuilt/MCP runs. Counted as units in the pass rate. */
		outcomeExpectations: z.array(z.string().min(1)).optional(),
		/**
		 * Removed in favour of the process/outcome split. Declared as a forbidden key (rather
		 * than dropped from the shape) so a legacy fixture fails loudly with a migration hint,
		 * instead of having its assertions silently stripped — which would undercount eval units
		 * and inflate the pass rate.
		 */
		buildExpectations: z
			.never({
				invalid_type_error:
					'`buildExpectations` is no longer supported — split it into `processExpectations` (about the build conversation) and `outcomeExpectations` (about the resulting workflow). See evaluations/README.md.',
			})
			.optional(),
		/**
		 * Credentials visible to this case's build. Created for real before the
		 * build and pinned as the thread's entire credential view; omitted → the
		 * build sees no credentials.
		 */
		credentials: z
			.array(
				z.object({
					// Validated against the seeder's templates so an authoring typo fails
					// at case-load time instead of per-build as an agent failure.
					type: z
						.string()
						.min(1)
						.refine((t) => SUPPORTED_CREDENTIAL_TYPES.has(t), {
							message: `unknown credential type — add a template to evaluations/credentials/seeder.ts (supported: ${[...SUPPORTED_CREDENTIAL_TYPES].join(', ')})`,
						}),
					name: z.string().min(1).optional(),
				}),
			)
			.optional(),
		/** Synthetic seed file (relative path), resolved + validated at case load.
		 *  Synthetic fixtures only; real conversations use `seedThread`. */
		seedFile: z.string().min(1).optional(),
		/** Prose turns seeded as plain-text history (no tool calls / workflows). */
		priorConversation: z.array(ConversationTurnSchema).min(1).optional(),
		/** Reproduce a real conversation from its LangSmith trace at run time (seed =
		 *  before the last user message, live = that message). Commits only the thread
		 *  id; workspace auto-discovered. Supplies the live turn, so `conversation` is
		 *  optional (continues after it). */
		seedThread: z
			.object({
				threadId: z.string().min(1),
				project: z.string().min(1).optional(),
				/** LangSmith host the source trace lives on (dual-tenant reads during the
				 *  US→EU migration). Omit ⇒ the eval's home (EU) tenant, so existing cases
				 *  are unchanged. A US-sourced case carries the US host; the harness maps
				 *  host→key via env (LANGSMITH_API_KEY_US). */
				endpoint: z.string().url().optional(),
			})
			.optional(),
		/**
		 * Logical groupings this case belongs to (e.g. `['pr', 'full']`). Used by
		 * the eval CLI's `--tier` flag and propagated to LangSmith as example
		 * splits, so subsets can be evaluated and compared independently. Defaults
		 * to `['full']` — cases without this field run in the full suite only.
		 */
		datasets: z.array(z.string()).min(1).default(DEFAULT_DATASETS),
	})
	// `.strict()` so any key outside the schema (a legacy `buildExpectations`, a typo'd
	// `outcomeExpectaiton`, etc.) fails at case-load instead of being silently stripped.
	.strict();

/** The keys n8n's case schema accepts. Exported so non-harness emitters (the
 *  lang-tracer normalizer) can WHITELIST an exported case down to exactly these —
 *  the schema is `.strict()`, so any extra key LangTracer attaches (id, name,
 *  suiteId, timestamps, …) fails the whole suite load. Whitelisting the allowed
 *  set is robust where blacklisting the few keys we happen to know today is not. */
export const WORKFLOW_TEST_CASE_KEYS = Object.keys(workflowTestCaseObjectSchema.shape);

// At most one seeding mode, and a source for the live turn.
export const WorkflowTestCaseSchema = workflowTestCaseObjectSchema
	.refine((c) => [c.seedFile, c.priorConversation, c.seedThread].filter(Boolean).length <= 1, {
		message:
			'seedFile, priorConversation and seedThread are mutually exclusive — pick one seeding mode',
	})
	.refine((c) => c.seedThread !== undefined || c.conversation !== undefined, {
		message:
			'a case needs a conversation, or a seedThread (which supplies the live turn from the trace)',
	});

export type WorkflowTestCaseInput = z.infer<typeof WorkflowTestCaseSchema>;

// Reconstruct a conversation seed from a LangSmith trace at run time: pull the
// thread's runs, rebuild the message log, split at the last user turn (before =
// seed, last = live), and reconstruct each seed workflow from its source at the
// build boundary. Transient: traces retain ~14 days.

import { isRecord } from '@n8n/utils';
import { Client } from 'langsmith';
import type { Run } from 'langsmith/schemas';

import type { ConversationSeed } from './conversation-seed';
import { parseSeedWorkflowCode } from './parse-seed-workflow';
import { DOMAIN_TOOL_IDS } from '../../src/tools/tool-ids';

/** Default project that instance-ai conversations are traced to (same name in
 *  every workspace). Override per case with `seedThread.project` if it differs. */
const DEFAULT_SOURCE_PROJECT = 'instance-ai';

// Reference the live tool-id so a rename there follows here (or breaks the import).
// patch/submit-workflow were removed in #32545 but stay for older traces.
const WORKFLOW_BUILD_TOOLS = new Set<string>([
	DOMAIN_TOOL_IDS.BUILD_WORKFLOW,
	'patch-workflow',
	'submit-workflow',
]);

// Workspace tools (@n8n/agents) whose ops mutate file content we replay. The names
// live here only; a contract test pins them — and the arg keys below — against the
// live tool set + Zod schema, so a rename in @n8n/agents fails CI loudly instead of
// silently no-op'ing a mutation (the same drift class #32545 caused).
const WORKSPACE_TOOL = {
	WRITE: 'workspace_write_file',
	APPEND: 'workspace_append_file',
	STR_REPLACE: 'workspace_str_replace_file',
	BATCH_STR_REPLACE: 'workspace_batch_str_replace_file',
	MOVE: 'workspace_move_file',
	COPY: 'workspace_copy_file',
	DELETE: 'workspace_delete_file',
} as const;

/** Input keys the replay reads per tool — pinned against the live Zod schema. */
export const REPLAYED_WORKSPACE_TOOL_ARGS: Record<string, readonly string[]> = {
	[WORKSPACE_TOOL.WRITE]: ['path', 'content'],
	[WORKSPACE_TOOL.APPEND]: ['path', 'content'],
	[WORKSPACE_TOOL.STR_REPLACE]: ['path', 'old_str', 'new_str'],
	[WORKSPACE_TOOL.BATCH_STR_REPLACE]: ['path', 'replacements'],
	[WORKSPACE_TOOL.MOVE]: ['src', 'dest'],
	[WORKSPACE_TOOL.COPY]: ['src', 'dest'],
	[WORKSPACE_TOOL.DELETE]: ['path'],
};

/** Live filesystem tools we deliberately don't replay (reads + dir ops) — listed so
 *  the contract test can prove every live filesystem tool is classified. */
export const IGNORED_WORKSPACE_TOOLS: readonly string[] = [
	'workspace_read_file',
	'workspace_list_files',
	'workspace_file_stat',
	'workspace_mkdir',
	'workspace_rmdir',
];

// The source thread may live in a different workspace than the eval writes to
// (e.g. seed from prod, trace to staging). A PAT spans workspaces, so we
// enumerate them and find the one holding the thread; reads are read-only.
//
// Reads are also dual-tenant: during the US→EU migration a US-sourced case
// carries `seedThread.endpoint` = the US host, while results always write to the
// home (EU) tenant elsewhere. `configFor` maps an endpoint → host + key via env.

/** The langsmith SDK's default endpoint is the US tenant, so an unset
 *  LANGSMITH_ENDPOINT silently means US. The eval env sets it to the home host. */
const US_DEFAULT_ENDPOINT = 'https://api.smith.langchain.com';

/** Bare host the langsmith Client wants as `apiUrl` (it appends paths itself):
 *  a trailing slash and an optional `/api/v1` suffix stripped. */
function bareHost(raw: string): string {
	return raw.replace(/\/+$/, '').replace(/\/api\/v1$/, '');
}

/**
 * Resolve the LangSmith host + key to READ a seed trace from, by endpoint.
 * Omitted ⇒ the eval's home tenant (its own env), so existing cases are
 * unchanged. The home host uses the home key; the secondary (US) host uses
 * LANGSMITH_API_KEY_US. A non-home host with no configured key THROWS rather
 * than silently read with the home key — which would query the wrong tenant and
 * report the thread as missing. Writes never go through here; they stay home.
 */
export function configFor(endpoint?: string): { apiUrl: string; apiKey: string } {
	const homeHost = bareHost(
		process.env.LANGSMITH_ENDPOINT ?? process.env.LANGCHAIN_ENDPOINT ?? US_DEFAULT_ENDPOINT,
	);
	const homeKey = process.env.LANGSMITH_API_KEY ?? process.env.LANGCHAIN_API_KEY ?? '';
	if (!endpoint) return { apiUrl: homeHost, apiKey: homeKey };

	const host = bareHost(endpoint);
	if (host === homeHost) return { apiUrl: host, apiKey: homeKey };

	const usHost = bareHost(process.env.LANGSMITH_ENDPOINT_US ?? US_DEFAULT_ENDPOINT);
	if (host === usHost) {
		const usKey = process.env.LANGSMITH_API_KEY_US ?? '';
		if (!usKey) {
			throw new Error(
				`seedThread.endpoint "${endpoint}" is the secondary (US) tenant but LANGSMITH_API_KEY_US is not set — refusing to read it with the home key. Set LANGSMITH_API_KEY_US.`,
			);
		}
		return { apiUrl: usHost, apiKey: usKey };
	}
	throw new Error(
		`seedThread.endpoint "${endpoint}" matches no configured LangSmith tenant (home: ${homeHost}; secondary: ${usHost}). Set LANGSMITH_ENDPOINT_US + LANGSMITH_API_KEY_US, or omit endpoint to use the home tenant.`,
	);
}

/** Workspaces a key can access on a host. Returns [] on any failure so the
 *  caller falls back to the key's default workspace. */
async function listAccessibleWorkspaces(
	apiUrl: string,
	apiKey: string,
): Promise<Array<{ id: string; name: string }>> {
	if (!apiKey) return [];
	try {
		const res = await fetch(`${apiUrl}/api/v1/workspaces`, { headers: { 'x-api-key': apiKey } });
		if (!res.ok) return [];
		const data: unknown = await res.json();
		if (!Array.isArray(data)) return [];
		return data.flatMap((entry) => {
			if (typeof entry !== 'object' || entry === null) return [];
			const record = entry as Record<string, unknown>;
			const id = asString(record.id);
			const name = asString(record.display_name) ?? asString(record.name) ?? id;
			return id ? [{ id, name: name ?? id }] : [];
		});
	} catch {
		return [];
	}
}

/** Seams for unit-testing workspace discovery without the network. */
export interface SeedDiscoveryDeps {
	listWorkspaces: () => Promise<Array<{ id: string; name: string }>>;
	clientForWorkspace: (workspaceId: string) => Client;
	ambientClient: () => Client;
}

/** Build discovery deps bound to one tenant (host + key resolved from the seed
 *  ref's endpoint). All three seams target that host, so cross-workspace
 *  discovery stays within the chosen tenant. */
function discoveryDepsFor(endpoint?: string): SeedDiscoveryDeps {
	const { apiUrl, apiKey } = configFor(endpoint);
	return {
		listWorkspaces: async () => await listAccessibleWorkspaces(apiUrl, apiKey),
		clientForWorkspace: (workspaceId) => new Client({ apiUrl, apiKey, workspaceId }),
		ambientClient: () => new Client({ apiUrl, apiKey }),
	};
}

/** Thrown when a thread has no runs in the queried (workspace, project) — used
 *  as control flow during discovery to advance to the next workspace. */
class ThreadNotInWorkspaceError extends Error {}

export interface SeedThreadRef {
	threadId: string;
	/** Override the LangSmith project to read the source trace from. */
	project?: string;
	/** LangSmith host the source trace lives on. Omit ⇒ the eval's home tenant.
	 *  Maps host→key via env (home key for the home host, LANGSMITH_API_KEY_US for
	 *  the US host); an unknown/unkeyed host throws rather than read the wrong tenant. */
	endpoint?: string;
}

export interface ReconstructedSeed {
	seed: ConversationSeed;
	/** The thread's last genuine user message — sent live, not seeded. */
	liveTurn: string;
	/** Provenance, for logging. */
	runCount: number;
	sourceProject: string;
	/** Workspace the thread was found in (when auto-discovered). */
	sourceWorkspace?: string;
}

function metadata(run: Run): Record<string, unknown> {
	return ((run.extra ?? {}) as { metadata?: Record<string, unknown> }).metadata ?? {};
}

function asString(value: unknown): string | undefined {
	return typeof value === 'string' ? value : undefined;
}

/** A genuine user turn: a 'turn' root with free-text `inputs.message`. System
 *  control inputs (e.g. `<workflow-setup-required>`) are angle-bracket tags —
 *  matched as a leading `<tag>`, not any `<`, so real messages like "<3" stay. */
function userMessageOf(run: Run): string | undefined {
	const message = asString(run.inputs?.message);
	if (run.name !== 'turn' || !message || /^<[a-z][\w-]*>/i.test(message)) return undefined;
	return message;
}

/** LangSmith redacts the `credentials:` key in captured SDK code; restore the
 *  opener so the code parses (secret values were never captured anyway). */
function unredactCode(code: string): string {
	return code.replace(/\[REDACTED\]/g, 'credentials: {');
}

/** A HITL suspend artifact (the pending request, no result) — dropped in favour
 *  of its resume run, which holds both request and answer. */
function isSuspendArtifact(output: unknown): boolean {
	if (!isRecord(output)) return false;
	if (output.deferred === true) return true;
	return isRecord(output.payload) && typeof output.payload.inputType === 'string';
}

/** A HITL request envelope: `{ payload: { requestId, … } }` — emitted by both the
 *  suspend and resume halves of ask-user / setup-card. Used (with the absence of
 *  a pending id) to identify the suspend half to drop. */
function isHitlRequestEnvelope(output: unknown): boolean {
	return (
		isRecord(output) && isRecord(output.payload) && typeof output.payload.requestId === 'string'
	);
}

/** Top-level fields that carry data-table row values across the data-table
 *  tools (insert/upsert/update take `rows`; reads return `data`). */
const DATA_TABLE_ROW_FIELDS = new Set(['rows', 'data']);

/** Replace data-table row arrays with an omission marker, keeping the rest of
 *  the payload — so seeded history carries no real (PII) row values. */
function redactDataTableRowPayload(value: unknown): Record<string, unknown> {
	if (!isRecord(value)) return {};
	const out: Record<string, unknown> = {};
	for (const [key, val] of Object.entries(value)) {
		out[key] =
			DATA_TABLE_ROW_FIELDS.has(key) && Array.isArray(val) ? `<${val.length} row(s) omitted>` : val;
	}
	return out;
}

interface TextBlock {
	type: 'text';
	text: string;
}
interface ToolCallBlock {
	type: 'tool-call';
	toolCallId: string;
	toolName: string;
	state: 'resolved';
	input: unknown;
	output: unknown;
}

/**
 * Reconstruct a thread's seed + live turn. The workspace holding the thread is
 * auto-discovered (the user only supplies a thread id); pass an explicit
 * `client` to bypass discovery (tests).
 *
 * Throws when the thread isn't found in any accessible workspace (trace aged out
 * or wrong project), or when it has fewer than two user turns.
 */
export async function reconstructSeedFromThread(
	ref: SeedThreadRef,
	client?: Client,
	deps?: SeedDiscoveryDeps,
): Promise<ReconstructedSeed> {
	const project = ref.project ?? DEFAULT_SOURCE_PROJECT;
	// An explicit client (tests) reads that one source; otherwise auto-discover
	// within the ref's tenant. Explicit deps (tests) override tenant resolution.
	if (client) return await reconstructWithClient(ref, client, project);
	return await discoverAndReconstruct(ref, project, deps ?? discoveryDepsFor(ref.endpoint));
}

/** Find the workspace holding the thread and reconstruct from it. Falls back to
 *  the key's default workspace when workspaces can't be enumerated. */
async function discoverAndReconstruct(
	ref: SeedThreadRef,
	project: string,
	deps: SeedDiscoveryDeps,
): Promise<ReconstructedSeed> {
	const workspaces = await deps.listWorkspaces();
	if (workspaces.length === 0) {
		return await reconstructWithClient(ref, deps.ambientClient(), project);
	}
	const tried: string[] = [];
	for (const workspace of workspaces) {
		tried.push(workspace.name);
		try {
			const result = await reconstructWithClient(
				ref,
				deps.clientForWorkspace(workspace.id),
				project,
			);
			return { ...result, sourceWorkspace: workspace.name };
		} catch (error) {
			// Not in this workspace → try the next; anything else (found but not
			// seedable, drift) is a real problem and propagates.
			if (error instanceof ThreadNotInWorkspaceError) continue;
			throw error;
		}
	}
	throw new Error(
		`Thread ${ref.threadId} not found in project "${project}" across ${String(workspaces.length)} workspace(s): ${tried.join(', ')}. The trace may have aged out (~14-day base retention), or the project name differs (set seedThread.project).`,
	);
}

/** Pull a thread's runs from one client/project and rebuild the seed + live turn. */
async function reconstructWithClient(
	ref: SeedThreadRef,
	client: Client,
	sourceProject: string,
): Promise<ReconstructedSeed> {
	const runs: Run[] = [];
	// Fetch only the run_types reconstruction uses — root `chain` turns + `tool` runs.
	// Paging every run_type (the llm/nested bulk is usually the majority) multiplied
	// /runs/query calls and tripped LangSmith rate limits on long threads. No is_root
	// filter: tools are non-root, so it can't be expressed as a single boolean.
	for await (const run of client.listRuns({
		projectName: sourceProject,
		filter: `and(eq(thread_id, "${ref.threadId}"), or(eq(run_type, "chain"), eq(run_type, "tool")))`,
	})) {
		runs.push(run);
	}
	if (runs.length === 0) {
		// Recognised by discovery to advance to the next workspace; the message
		// still reads well if it surfaces directly (explicit-client path).
		throw new ThreadNotInWorkspaceError(
			`No runs for thread ${ref.threadId} in LangSmith project "${sourceProject}" — the trace may have aged out (~14-day base retention) or the project name is wrong.`,
		);
	}

	const byStartTime = (a: Run, b: Run) =>
		new Date(a.start_time).getTime() - new Date(b.start_time).getTime();
	const rootRuns = runs.filter((r) => r.run_type === 'chain' && !r.parent_run_id).sort(byStartTime);
	const toolRuns = runs.filter((r) => r.run_type === 'tool').sort(byStartTime);

	// Split point: the last genuine user turn is sent live; everything strictly
	// before it is the seed.
	const userTurns = rootRuns.filter((r) => userMessageOf(r) !== undefined);
	if (userTurns.length < 2) {
		throw new Error(
			`Thread ${ref.threadId} has ${userTurns.length} user turn(s) — need ≥2 to seed (one prior + one live). Use a plain conversation case instead.`,
		);
	}
	const liveTurnRun = userTurns[userTurns.length - 1];
	const boundaryMs = new Date(liveTurnRun.start_time).getTime();
	const liveTurn = userMessageOf(liveTurnRun)!;

	const messages = buildSeedMessages(rootRuns, toolRuns, boundaryMs);
	if (messages.length === 0) {
		throw new Error(
			`Thread ${ref.threadId} reconstructed to zero seed messages before the live turn — the trace shape may have drifted (expected root runs named 'turn' with inputs.message / outputs.response).`,
		);
	}
	const workflows = buildSeedWorkflows(toolRuns, boundaryMs, ref.threadId);
	const dataTables = buildSeedDataTables(toolRuns, boundaryMs);

	return {
		seed: {
			source: { kind: 'langsmith', threadId: ref.threadId, sourceProject },
			messages,
			workflows,
			dataTables,
		},
		liveTurn,
		runCount: runs.length,
		sourceProject,
	};
}

/** Rebuild the native message log for every run before the seed boundary. */
function buildSeedMessages(
	rootRuns: Run[],
	toolRuns: Run[],
	boundaryMs: number,
): Array<Record<string, unknown>> {
	const toolsByRoot = new Map<string, Run[]>();
	for (const tool of toolRuns) {
		const rootId = asString(metadata(tool).langsmith_root_run_id) ?? tool.trace_id ?? '';
		const list = toolsByRoot.get(rootId) ?? [];
		list.push(tool);
		toolsByRoot.set(rootId, list);
	}

	const emittedToolCallIds = new Set<string>();
	const messages: Array<Record<string, unknown>> = [];

	for (const root of rootRuns) {
		if (new Date(root.start_time).getTime() >= boundaryMs) break;

		const userText = userMessageOf(root);
		if (userText) {
			messages.push({
				id: `${root.id}-user`,
				role: 'user',
				type: 'llm',
				createdAt: new Date(root.start_time).toISOString(),
				content: [{ type: 'text', text: userText }],
			});
		}

		const content: Array<TextBlock | ToolCallBlock> = [];
		const responseText = asString(root.outputs?.response);
		if (responseText) content.push({ type: 'text', text: responseText });

		for (const tool of toolsByRoot.get(root.id) ?? []) {
			// HITL tools split into a suspend run + a later resume run (no shared id):
			// drop the suspend, keep the resume which holds request + answer.
			if (isSuspendArtifact(tool.outputs)) continue;
			const pendingId = asString(metadata(tool).pending_tool_call_id);
			// Setup-card suspend half (request envelope, no pending id) — its resume is kept.
			if (!pendingId && isHitlRequestEnvelope(tool.outputs)) continue;
			const toolCallId = pendingId ?? tool.id;
			if (emittedToolCallIds.has(toolCallId)) continue;
			emittedToolCallIds.add(toolCallId);
			// Redact data-table row payloads: seeded messages are written to the eval
			// instance + shown to the judge, so real (PII) rows must not ride along.
			const isDataTable = tool.name.startsWith('data-tables');
			content.push({
				type: 'tool-call',
				toolCallId,
				toolName: tool.name,
				state: 'resolved',
				input: isDataTable ? redactDataTableRowPayload(tool.inputs) : (tool.inputs ?? {}),
				output: isDataTable ? redactDataTableRowPayload(tool.outputs) : (tool.outputs ?? {}),
			});
		}

		if (content.length > 0) {
			messages.push({
				id: `${root.id}-assistant`,
				role: 'assistant',
				type: 'llm',
				// +1ms so the assistant reply orders after its user turn.
				createdAt: new Date(new Date(root.start_time).getTime() + 1).toISOString(),
				content,
			});
		}
	}

	return messages;
}

/** Replay one content-mutating workspace tool onto the reconstructed file map.
 *  Returns false when an edit can't be applied faithfully (a str-replace whose
 *  anchor is absent) — the reconstruction has diverged from the real sandbox. */
function applyFileMutation(files: Map<string, string>, tool: Run): boolean {
	const input = isRecord(tool.inputs) ? tool.inputs : {};
	// A failed edit left the real file unchanged — treat as a no-op (no divergence).
	if (isRecord(tool.outputs) && tool.outputs.success === false) return true;
	if (tool.name === WORKSPACE_TOOL.WRITE) {
		const path = asString(input.path);
		const content = asString(input.content);
		if (path && content !== undefined) files.set(path, content);
		return true;
	}
	if (tool.name === WORKSPACE_TOOL.APPEND) {
		const path = asString(input.path);
		if (path) files.set(path, (files.get(path) ?? '') + (asString(input.content) ?? ''));
		return true;
	}
	if (tool.name === WORKSPACE_TOOL.STR_REPLACE) {
		// The tool requires one exact, unique match; mirror it (first occurrence).
		const path = asString(input.path);
		const current = path !== undefined ? files.get(path) : undefined;
		const oldStr = asString(input.old_str);
		const newStr = asString(input.new_str);
		if (path === undefined || current === undefined || !oldStr || newStr === undefined) return true;
		if (!current.includes(oldStr)) return false;
		files.set(path, current.replace(oldStr, newStr));
		return true;
	}
	if (tool.name === WORKSPACE_TOOL.BATCH_STR_REPLACE) {
		// The real tool is atomic — it validates every anchor up front and applies
		// all or nothing (@n8n/ai-utilities TextEditorDocument.executeBatch). Mirror
		// that, like single str-replace: any missing anchor → file untouched, diverged.
		const path = asString(input.path);
		const current = path !== undefined ? files.get(path) : undefined;
		if (path === undefined || current === undefined) return true;
		const replacements = Array.isArray(input.replacements) ? input.replacements : [];
		let next = current;
		for (const replacement of replacements) {
			if (!isRecord(replacement)) continue;
			const oldStr = asString(replacement.old_str);
			const newStr = asString(replacement.new_str);
			if (!oldStr || newStr === undefined) continue;
			if (!next.includes(oldStr)) return false;
			next = next.replace(oldStr, newStr);
		}
		files.set(path, next);
		return true;
	}
	if (tool.name === WORKSPACE_TOOL.MOVE || tool.name === WORKSPACE_TOOL.COPY) {
		const src = asString(input.src);
		const dest = asString(input.dest);
		const content = src !== undefined ? files.get(src) : undefined;
		if (src !== undefined && dest !== undefined && content !== undefined) {
			files.set(dest, content);
			if (tool.name === WORKSPACE_TOOL.MOVE) files.delete(src);
		}
		return true;
	}
	if (tool.name === WORKSPACE_TOOL.DELETE) {
		const path = asString(input.path);
		if (path) files.delete(path);
		return true;
	}
	return true; // read/list/grep/etc. — no content change
}

/** Reconstruct the seed's workflows: the latest successful build per workflow id
 *  before the boundary. Post-#32545 the builder builds from a workspace file
 *  (`build-workflow {filePath}`, no inline code), so the source is that file
 *  replayed from the workspace ops; inline `code` and `get-as-code` are fallbacks.
 *  Only files an actual build references become workflows. */
function buildSeedWorkflows(
	toolRuns: Run[],
	boundaryMs: number,
	threadId: string,
): ConversationSeed['workflows'] {
	const files = new Map<string, string>();
	const divergedPaths = new Set<string>();
	const getAsCodeByWorkflowId = new Map<string, string>();
	// workflowId -> reconstructed source + name at its latest successful build.
	const builtByWorkflowId = new Map<string, { code: string; diverged: boolean; name?: string }>();
	// Workflow ids with a build-shaped run (source in, success + workflowId out),
	// name-independent — drives the drift tripwire below.
	const buildSignalIds = new Set<string>();

	for (const tool of toolRuns) {
		if (new Date(tool.start_time ?? 0).getTime() >= boundaryMs) continue;

		if (tool.name.startsWith('workspace_')) {
			const path = asString((isRecord(tool.inputs) ? tool.inputs : {}).path);
			const applied = applyFileMutation(files, tool);
			// A full write replaces the file, healing any earlier divergence.
			if (tool.name === WORKSPACE_TOOL.WRITE) {
				if (path !== undefined) divergedPaths.delete(path);
			} else if (!applied && path !== undefined) {
				divergedPaths.add(path);
			}
			continue;
		}

		const out = isRecord(tool.outputs) ? tool.outputs : {};
		if (tool.name.includes('get-as-code')) {
			const code = asString(out.code);
			const workflowId = asString(out.workflowId);
			if (code && workflowId) getAsCodeByWorkflowId.set(workflowId, code);
		}

		const workflowId = asString(out.workflowId);
		if (out.success !== true || workflowId === undefined) continue;
		const input = isRecord(tool.inputs) ? tool.inputs : {};
		const filePath = asString(input.filePath);
		const inlineCode = asString(input.code);
		if (filePath === undefined && inlineCode === undefined) continue;
		// A build happened for this id (even if the tool's name isn't recognised).
		buildSignalIds.add(workflowId);
		if (!WORKFLOW_BUILD_TOOLS.has(tool.name)) continue;
		// Current builder: the workspace file's content at this build. Legacy: inline code.
		const code = filePath !== undefined ? (files.get(filePath) ?? '') : (inlineCode ?? '');
		const diverged = filePath !== undefined ? divergedPaths.has(filePath) : false;
		// Sorted ascending → the latest successful build wins.
		builtByWorkflowId.set(workflowId, { code, diverged, name: asString(out.workflowName) });
	}

	const workflows: ConversationSeed['workflows'] = [];
	const degraded: string[] = [];
	const skipped: string[] = [];
	for (const [workflowId, built] of builtByWorkflowId) {
		const getAsCode = getAsCodeByWorkflowId.get(workflowId) ?? '';
		// Resolve in descending order of trust: clean file replay, then a
		// `get-as-code` capture, then a diverged replay as a last resort.
		const candidates: Array<[string, string]> = [
			['replay', built.diverged ? '' : built.code],
			['get-as-code', getAsCode],
			['diverged-replay', built.diverged ? built.code : ''],
		];
		let resolved: ReturnType<typeof tryParseSeedWorkflow>;
		let via = '';
		for (const [label, code] of candidates) {
			if (code === '') continue;
			resolved = tryParseSeedWorkflow(unredactCode(code));
			if (resolved) {
				via = label;
				break;
			}
		}
		if (!resolved) {
			skipped.push(workflowId);
			continue;
		}
		if (via !== 'replay') degraded.push(`${workflowId}→${via}`);
		workflows.push({
			id: workflowId,
			name: built.name ?? resolved.name ?? 'workflow',
			nodes: resolved.nodes,
			connections: resolved.connections,
		});
	}
	if (degraded.length > 0) {
		console.warn(
			`[seed] Thread ${threadId}: ${degraded.length} workflow(s) reconstructed via a fallback source (file replay diverged — likely an untracked shell edit); verify before trusting: ${degraded.join(', ')}`,
		);
	}
	if (skipped.length > 0) {
		console.warn(
			`[seed] Thread ${threadId}: ${skipped.length} built workflow(s) could not be reconstructed and were skipped: ${skipped.join(', ')}`,
		);
	}

	// Builds happened but we recovered nothing → throw rather than silently seed 0
	// workflows (reported as a framework_issue; the message names the likely cause).
	if (buildSignalIds.size > 0 && workflows.length === 0) {
		throw new Error(
			`Thread ${threadId}: ${buildSignalIds.size} workflow(s) were built in the trace but reconstruction recovered 0 — the build tool was likely renamed or its input/output shape changed (e.g. inline-code → filePath). Update reconstruction (WORKFLOW_BUILD_TOOLS / source extraction in buildSeedWorkflows).`,
		);
	}
	if (workflows.length < buildSignalIds.size) {
		console.warn(
			`[seed] Thread ${threadId}: reconstructed ${workflows.length}/${buildSignalIds.size} built workflow(s) — partial; check for trace-shape drift if unexpected.`,
		);
	}

	return workflows;
}

/** Parse reconstructed SDK code into workflow JSON, returning undefined instead
 *  of throwing so a caller can fall back to another source. */
function tryParseSeedWorkflow(
	code: string,
):
	| { name?: string; nodes: Array<Record<string, unknown>>; connections: Record<string, unknown> }
	| undefined {
	try {
		const { workflow } = parseSeedWorkflowCode(code);
		return {
			name: workflow.name,
			nodes: (workflow.nodes ?? []) as unknown as Array<Record<string, unknown>>,
			connections: (workflow.connections ?? {}) as Record<string, unknown>,
		};
	} catch {
		return undefined;
	}
}

type DataTableColumnType = 'string' | 'number' | 'boolean' | 'date';
const DATA_TABLE_COLUMN_TYPES = new Set<string>(['string', 'number', 'boolean', 'date']);
function isDataTableColumnType(value: string): value is DataTableColumnType {
	return DATA_TABLE_COLUMN_TYPES.has(value);
}

/** Reconstruct the seed's data tables, schema only — enough for a restored
 *  workflow's data-table node to resolve. Rows are deliberately not pulled
 *  (highest-PII payload). Detected by shape (`create` returns `table.id` +
 *  `table.columns`), so a renamed tool still reconstructs. */
function buildSeedDataTables(toolRuns: Run[], boundaryMs: number): ConversationSeed['dataTables'] {
	const created = new Map<string, ConversationSeed['dataTables'][number]>();

	for (const tool of toolRuns) {
		if (new Date(tool.start_time ?? 0).getTime() >= boundaryMs) continue;
		const out = isRecord(tool.outputs) ? tool.outputs : {};

		// A `create`: output carries the new table's id, name and columns.
		const table = isRecord(out.table) ? out.table : undefined;
		const tableId = table ? asString(table.id) : undefined;
		if (!table || !tableId || !Array.isArray(table.columns)) continue;
		const columns = table.columns.flatMap((col) => {
			if (!isRecord(col)) return [];
			const name = asString(col.name);
			const type = asString(col.type);
			if (!name || !type || !isDataTableColumnType(type)) return [];
			return [{ name, type }];
		});
		created.set(tableId, { id: tableId, name: asString(table.name) ?? 'data table', columns });
	}

	return [...created.values()];
}

import { WORKFLOW_TEST_CASE_KEYS } from '../data/workflows/schema';

/** Keys n8n's `.strict()` case schema accepts — anything else must be stripped. */
const ALLOWED_KEYS = new Set(WORKFLOW_TEST_CASE_KEYS);

/** Fold lang-tracer's legacy `buildExpectations` into `outcomeExpectations` (the key
 *  n8n's schema forbids). Outcome runs in every build mode. No-ops post-split. */
export function normalizeExportedCase(raw: unknown): unknown {
	if (raw === null || typeof raw !== 'object' || Array.isArray(raw)) return raw;

	const obj: Record<string, unknown> = { ...raw };

	if (Array.isArray(obj.buildExpectations)) {
		const legacy = obj.buildExpectations.filter((s): s is string => typeof s === 'string');
		const existing = Array.isArray(obj.outcomeExpectations)
			? obj.outcomeExpectations.filter((s): s is string => typeof s === 'string')
			: [];
		const merged = [...existing, ...legacy];
		if (merged.length > 0) obj.outcomeExpectations = merged;
		delete obj.buildExpectations;
	}

	// Whitelist to the schema's accepted keys. LangTracer attaches export-only keys
	// (id, name, suiteId, timestamps, the dispatch-only prompt/scenarios, …); n8n's
	// schema is `.strict()` and the loader aggregates errors, so a single stray key
	// fails the whole suite. Stripping to the allowed set is robust where deleting
	// the two keys we happen to know today is not.
	const cleaned: Record<string, unknown> = {};
	for (const [key, value] of Object.entries(obj)) {
		if (ALLOWED_KEYS.has(key)) cleaned[key] = value;
	}
	return cleaned;
}

