import { ReactNode } from "react"
import { JsonViewSection } from "../common/json-view-section"
import { MetadataSection } from "../common/metadata-section"
import { RequiredPermissionsSection } from "../common/required-permissions-section"
import { LayoutComposer } from "./layout-composer"

export type DetailPageDefaultsOptions = {
  /** Render the metadata section. @default true */
  metadata?: boolean
  /** Render the JSON view section. @default true */
  jsonView?: boolean
  /** Render the required-permissions section. @default true */
  permissions?: boolean
}

/**
 * Returns the sections common to detail pages (metadata, JSON view, and
 * required permissions), each wrapped in a `LayoutComposer.Entry` with a
 * stable id so saved user preferences survive component renames.
 *
 * All three render by default. Pass an options object to opt out of any a
 * given page doesn't use, so the page renders exactly the set it always had:
 *
 * ```tsx
 * sections={{ main: <>{...coreContent}{detailPageDefaultEntries(entity)}</> }}
 * // metadata + json only:
 * {detailPageDefaultEntries(entity, { permissions: false })}
 * ```
 */
export function detailPageDefaultEntries(
  data: object,
  {
    metadata = true,
    jsonView = true,
    permissions = true,
  }: DetailPageDefaultsOptions = {}
): ReactNode {
  return (
    <>
      {metadata && (
        <LayoutComposer.Entry id="MetadataSection">
          <MetadataSection data={data} />
        </LayoutComposer.Entry>
      )}
      {jsonView && (
        <LayoutComposer.Entry id="JsonViewSection">
          <JsonViewSection data={data} />
        </LayoutComposer.Entry>
      )}
      {permissions && (
        <LayoutComposer.Entry id="RequiredPermissionsSection">
          <RequiredPermissionsSection />
        </LayoutComposer.Entry>
      )}
    </>
  )
}

import {
  Children,
  ComponentType,
  Fragment,
  ReactElement,
  ReactNode,
  isValidElement,
} from "react"
import { LayoutEntry } from "./entry"
import type { LayoutEntryProps } from "./entry"
import { LayoutPreference } from "./types"

// Both core entries and widgets carry a `render` thunk so the rest of the
// composer treats them uniformly: core entries return their prebuilt element
// (ignoring `data`), widgets render their component with the page `data`. The
// thunk is what keeps `data` out of the layout-model memo — rendering is
// deferred to call time rather than baked into the entry.
export type EntryRenderer = (data: unknown) => ReactNode

export type DisplayEntry = {
  widgetId: string
  render: EntryRenderer
  order: number
  hidden: boolean
}

export type RawEntry = {
  widgetId: string
  render: EntryRenderer
  naturalSection: string
}

/** Derives a stable string identifier from a React element's component type. */
function getElementName(element: ReactElement): string {
  const { type } = element
  if (typeof type === "string") {
    return type
  }
  return (
    (type as ComponentType).displayName ??
    (type as ComponentType).name ??
    "unknown"
  )
}

function isLayoutEntry(
  element: ReactElement
): element is ReactElement<LayoutEntryProps> {
  return element.type === LayoutEntry
}

/**
 * Resolves the identity segment for a core element. Prefers an explicit
 * `LayoutComposer.Entry` wrapper id (stable across renames and minification);
 * otherwise falls back to the component's display/function name.
 */
function getCoreEntryKey(element: ReactElement): string {
  if (isLayoutEntry(element)) {
    return element.props.id
  }
  return getElementName(element)
}

/**
 * Builds a core entry for every element across all sections, in source order.
 * Each entry renders its own prebuilt element.
 *
 * Duplicate ids (same component/name, or two anonymous elements) are
 * disambiguated with a `#n` suffix via a single `seen` map shared across all
 * sections — so two same-named entries in different sections still get distinct,
 * deterministic ids and don't collide on keys, drag ids, or preference lookups.
 * The id intentionally omits the section, so an entry keeps its identity (and
 * saved preference) when its natural section changes in code.
 */
export function buildCoreEntries(
  elementsBySection: Record<string, ReactElement[]>
): RawEntry[] {
  const entries: RawEntry[] = []
  const seen = new Map<string, number>()

  for (const [sectionName, elements] of Object.entries(elementsBySection)) {
    for (const el of elements) {
      const name = getCoreEntryKey(el)
      const base = `core:${name}`
      const count = seen.get(base) ?? 0
      seen.set(base, count + 1)
      const widgetId = count === 0 ? base : `${base}#${count + 1}`

      entries.push({
        widgetId,
        render: () => el,
        naturalSection: sectionName,
      })
    }
  }

  return entries
}

export function extractSectionElements(
  sections: Record<string, ReactNode>
): Record<string, ReactElement[]> {
  const result: Record<string, ReactElement[]> = {}
  for (const [sectionName, node] of Object.entries(sections)) {
    result[sectionName] = collectElements(node)
  }
  return result
}

/**
 * Flattens a section's children into individual ReactElements, unwrapping
 * fragments so each direct child component becomes its own customizer entry.
 */
function collectElements(node: ReactNode): ReactElement[] {
  const elements: ReactElement[] = []
  Children.forEach(node, (child) => {
    if (!isValidElement(child)) {
      return
    }
    if (child.type === Fragment) {
      const fragmentChildren = (child.props as { children?: ReactNode })
        .children
      elements.push(...collectElements(fragmentChildren))
      return
    }
    elements.push(child)
  })
  return elements
}

/**
 * Merges all entries (core + widgets) and applies a preference, returning a
 * map of effective-section → DisplayEntry[] sorted by order. Includes hidden
 * entries (with `hidden: true`) so the renderer can ghost them in edit mode.
 *
 * `validSections` is the set of section ids the active layout actually renders.
 * A stored `section` override that points at a section which no longer exists
 * (layout switched, section renamed/removed) is ignored so the entry falls back
 * to its natural section instead of vanishing into an unrendered bucket.
 */
export function buildDisplayEntries(
  raw: RawEntry[],
  preference: LayoutPreference,
  validSections: Set<string>
): Record<string, DisplayEntry[]> {
  const result: Record<string, DisplayEntry[]> = {}
  for (const entry of raw) {
    const pref = preference.widgets[entry.widgetId]
    const overrideSection =
      pref?.section && validSections.has(pref.section)
        ? pref.section
        : undefined
    const effectiveSection = overrideSection ?? entry.naturalSection
    // Entries with no saved order share order 0; their relative placement
    // (widgets before core, each group in source order) comes from insertion
    // order preserved by the stable sort below.
    const effectiveOrder = pref?.order ?? 0
    const hidden = pref?.hidden ?? false
    if (!result[effectiveSection]) {
      result[effectiveSection] = []
    }
    result[effectiveSection].push({
      widgetId: entry.widgetId,
      render: entry.render,
      order: effectiveOrder,
      hidden,
    })
  }
  for (const k of Object.keys(result)) {
    result[k].sort((a, b) => a.order - b.order)
  }
  return result
}

export const SECTION_TAIL_SUFFIX = "::tail"

export const isSectionTailId = (id: string) => id.endsWith(SECTION_TAIL_SUFFIX)

export const getSectionIdFromTailId = (id: string) =>
  id.slice(0, -SECTION_TAIL_SUFFIX.length)

// A section's trailing drop zone gets its own droppable id, derived from the
// section id, so the drag handlers can tell "dropped at the end of a section"
// apart from "dropped onto a specific entry". Kept here next to the component
// that renders it.
export const getSectionTailId = (sectionId: string) =>
  `${sectionId}${SECTION_TAIL_SUFFIX}`

import { Fragment, ReactNode } from "react"

export type LayoutEntryProps = {
  /** Stable identity for this entry. Survives component renames and minification. */
  id: string
  children: ReactNode
}

/**
 * Pins a stable identity to a layout entry. Use this to wrap sections whose
 * component name is unstable (subject to rename or minification), ensuring
 * any saved user preferences survive refactors.
 */
export function LayoutEntry({ children }: LayoutEntryProps) {
  return <Fragment>{children}</Fragment>
}

LayoutEntry.displayName = "LayoutEntry"

import { DndContext, DragOverlay } from "@dnd-kit/core"
import { Adjustments, AdjustmentsDone } from "@medusajs/icons"
import { Badge, Button, IconButton, Tooltip, usePrompt } from "@medusajs/ui"
import {
  ComponentType,
  Fragment,
  ReactNode,
  useCallback,
  useMemo,
  useState,
} from "react"
import { createPortal } from "react-dom"
import { useTranslation } from "react-i18next"
import { Outlet } from "react-router-dom"
import { useExtension } from "../../providers/extension-provider/use-extension"
import { useLayoutCustomizerTriggerHost } from "../../hooks/use-layout-customizer-trigger-host"
import {
  DisplayEntry,
  RawEntry,
  buildCoreEntries,
  buildDisplayEntries,
  extractSectionElements,
} from "./entries"
import { LayoutEntry } from "./entry"
import { SectionDropzone } from "./section-dropzone"
import { EntryContent, SortableEntry } from "./sortable-entry"
import type {
  LayoutPreference,
  SectionNameFor,
  Layouts,
  WidgetPreference,
} from "./types"
import { useLayoutDnd } from "../../hooks/use-layout-dnd"
import {
  useLayoutPreference,
  type LayoutScope,
} from "../../hooks/use-layout-preference"

type LayoutComposerProps<TLayoutId extends Layouts, TData> = {
  /**
   * The prefix used to derive widget injection zones, typically corresponds to the page.
   * E.g. `"login"`, `"product.list"`, `"product.details"` etc.
   */
  widgetsZonePrefix: string
  /**
   * The id of the layout that should be used to render the page. E.g `"core:two-column"` or `"core:single-column"`.
   */
  preferredLayoutId: TLayoutId
  /**
   * The content to render in each section of the layout, keyed by the
   * section names valid for `preferredLayoutId`.
   */
  sections: Record<SectionNameFor<TLayoutId>, ReactNode>
  /**
   * Data passed to the layout components(core + widgets) as props
   */
  data?: TData
  /**
   * Whether to render an `Outlet` after the layout, used to render modals such as drawers and dialogs.
   *
   * @default true
   */
  hasOutlet?: boolean
}

/**
 * Whether two preferences describe the same layout. A widget with no
 * meaningful overrides is treated as absent so that toggling a setting and
 * back — or simply switching between scopes without editing — doesn't register
 * as a change.
 */
function isSamePreference(a: LayoutPreference, b: LayoutPreference): boolean {
  const keys = new Set([...Object.keys(a.widgets), ...Object.keys(b.widgets)])
  for (const key of keys) {
    const aw = a.widgets[key]
    const bw = b.widgets[key]
    if (!!aw?.hidden !== !!bw?.hidden) {
      return false
    }
    if (aw?.order !== bw?.order) {
      return false
    }
    if (aw?.section !== bw?.section) {
      return false
    }
  }
  return true
}

const LayoutComposerRoot = <TLayoutId extends Layouts, TData>({
  widgetsZonePrefix,
  preferredLayoutId,
  sections,
  data,
  hasOutlet = true,
}: LayoutComposerProps<TLayoutId, TData>) => {
  const { getWidgetsForSections, getLayout } = useExtension()
  const {
    personalPreference,
    defaultPreference,
    activeScope,
    definedScope,
    setPreference,
    isSaving,
  } = useLayoutPreference(widgetsZonePrefix)
  const triggerHost = useLayoutCustomizerTriggerHost()
  const { t } = useTranslation()
  const prompt = usePrompt()

  const [editMode, setEditMode] = useState(false)
  const [draft, setDraft] = useState<LayoutPreference | null>(null)
  // Which configuration the current edit session is targeting: the user's
  // personal layout or the zone's shared default.
  const [editScope, setEditScope] = useState<LayoutScope>("personal")

  const preferenceForScope = useCallback(
    (scope: LayoutScope): LayoutPreference => {
      return scope === "default" ? defaultPreference : personalPreference
    },
    [defaultPreference, personalPreference]
  )

  const activePreference: LayoutPreference = useMemo(() => {
    return editMode && draft ? draft : preferenceForScope(activeScope)
  }, [editMode, draft, preferenceForScope, activeScope])

  // Whether the current draft actually differs from the persisted preference
  // for the scope being edited. Switching between scopes without making edits
  // leaves this false, so saving is a no-op confirmation we can streamline.
  const hasChanges = useMemo(() => {
    return editMode && draft
      ? !isSamePreference(draft, preferenceForScope(editScope))
      : false
  }, [editMode, draft, preferenceForScope, editScope])

  // TODO: Implement switching between compatible layouts
  const layoutId = preferredLayoutId

  const layout = getLayout(layoutId)

  // Derive the layout model: core + widget entries placed into their effective
  // sections with the active preference applied. Memoized so it isn't rebuilt
  // on unrelated re-renders (e.g. drag start) — only when the sections,
  // registered widgets, or active preference actually change.
  const { entriesBySection, widgetSectionMap, validSectionIds } =
    useMemo(() => {
      const coreElementsBySection = extractSectionElements(
        sections as Record<string, ReactNode>
      )
      const naturalWidgets = getWidgetsForSections(
        widgetsZonePrefix,
        layout?.sections?.map((s) => s.id) ?? []
      )

      // Build raw entries (core + widgets) at their natural sections. Relative
      // placement before any user preference comes purely from the order they
      // are pushed here, preserved by the stable sort in `buildDisplayEntries`.
      // Widgets are pushed after core entries so they render after by default —
      // If a configuration has been saved, newly added widget or core entry
      // (which has no saved order) surfaces at the top, otherwise it will be
      // placed at the bottom of the section.
      const rawEntries: RawEntry[] = buildCoreEntries(coreElementsBySection)
      for (const [naturalSection, widgets] of Object.entries(naturalWidgets)) {
        for (const w of widgets) {
          const WidgetComponent = w.Component as ComponentType<{
            data?: unknown
          }>
          rawEntries.push({
            widgetId: w.widgetId,
            render: (data) => <WidgetComponent data={data} />,
            naturalSection,
          })
        }
      }

      // Apply the active preference (draft when editing, persisted otherwise),
      // keeping hidden entries with `hidden: true` so we can ghost them in edit
      // mode.
      const validSectionIds = new Set(layout?.sections.map((s) => s.id) ?? [])
      const entriesBySection = buildDisplayEntries(
        rawEntries,
        activePreference,
        validSectionIds
      )

      // Maps each entry's widgetId to the section it currently renders in.
      // Shared by collision detection and the drag handlers to resolve the
      // active/over sections of a move.
      const widgetSectionMap: Record<string, string> = {}
      for (const [sectionId, entries] of Object.entries(entriesBySection)) {
        for (const e of entries) {
          widgetSectionMap[e.widgetId] = sectionId
        }
      }

      return {
        entriesBySection,
        widgetSectionMap,
        validSectionIds,
      }
    }, [
      sections,
      widgetsZonePrefix,
      layout,
      activePreference,
      getWidgetsForSections,
    ])

  const {
    sensors,
    collisionDetection,
    activeEntry,
    handleDragStart,
    handleDragOver,
    handleDragEnd,
  } = useLayoutDnd({
    entriesBySection,
    widgetSectionMap,
    validSectionIds,
    setDraft,
  })

  // Renders a single entry for the current mode: plain content at idle, a
  // sortable wrapper with chrome in edit mode. An entry that currently renders
  // nothing stays a sortable card showing a placeholder (see `SortableEntry`),
  // so it remains visible and placeable rather than collapsing to a bare row.
  const renderEntry = useCallback(
    (entry: DisplayEntry): ReactNode => {
      const content = entry.render(data)
      if (!editMode) {
        return <Fragment key={entry.widgetId}>{content}</Fragment>
      }
      return (
        <SortableEntry
          key={entry.widgetId}
          widgetId={entry.widgetId}
          order={entry.order}
          hidden={entry.hidden}
          onToggleHidden={() => toggleHidden(entry.widgetId)}
        >
          {content}
        </SortableEntry>
      )
    },
    [data, editMode]
  )

  function toggleHidden(widgetId: string) {
    setDraft((prev) => {
      if (!prev) {
        return prev
      }
      const current = prev.widgets[widgetId] ?? {}
      const nextWidget: WidgetPreference = {
        ...current,
        hidden: !current.hidden,
      }
      return {
        ...prev,
        widgets: { ...prev.widgets, [widgetId]: nextWidget },
      }
    })
  }

  function enterEdit() {
    setEditScope(activeScope)
    setDraft(preferenceForScope(activeScope))
    setEditMode(true)
  }

  // When the user clicks a scope badge while editing:
  // - If there are unsaved edits, keep the draft so the changes aren't lost
  //   and just retarget which scope they'll be saved to.
  // - If the draft is clean (no edits vs. the current scope), load the saved
  //   preference for the new scope so the user sees its real state.
  function switchScope(scope: LayoutScope) {
    if (!hasChanges) {
      setDraft(preferenceForScope(scope))
    }
    setEditScope(scope)
  }

  async function commitEdit() {
    if (editScope === "default" && hasChanges) {
      const confirmed = await prompt({
        title: t("layout.saveForEveryoneTitle"),
        description: t("layout.saveForEveryoneDescription"),
        confirmText: t("layout.saveForEveryone"),
        cancelText: t("actions.cancel"),
      })
      if (!confirmed) {
        return
      }
    }

    if (!draft) {
      setEditMode(false)
      return
    }

    setPreference(
      draft,
      { asDefault: editScope === "default" },
      {
        onSuccess: () => {
          setEditMode(false)
          setDraft(null)
        },
      }
    )
  }

  function cancelEdit() {
    setEditMode(false)
    setDraft(null)
  }

  const renderedSections: Record<string, ReactNode> = useMemo(() => {
    const sections: Record<string, ReactNode> = {}
    for (const section of layout?.sections ?? []) {
      const entries = entriesBySection[section.id] ?? []
      const visibleEntries = editMode
        ? entries
        : entries.filter((e) => !e.hidden)
      const renderedItems = visibleEntries.map(renderEntry)

      sections[section.id] = editMode ? (
        <SectionDropzone
          section={section}
          items={visibleEntries.map((e) => e.widgetId)}
        >
          {renderedItems}
        </SectionDropzone>
      ) : (
        renderedItems
      )
    }
    return sections
  }, [layout, entriesBySection, editMode, renderEntry])

  const LayoutComponent = layout?.Component
  if (!LayoutComponent) {
    return null
  }

  // Idle trigger tooltip: always explains the action, and when a layout has
  // been defined for this zone, adds whose layout the user is currently seeing.
  const triggerTooltip = definedScope ? (
    <div className="flex flex-col gap-y-0.5">
      <span>{t("layout.customizeLayout")}</span>
      <span className="text-ui-fg-subtle">
        {t(
          definedScope === "personal"
            ? "layout.viewingPersonalLayout"
            : "layout.viewingSystemLayout"
        )}
      </span>
    </div>
  ) : (
    t("layout.customizeLayout")
  )

  // Customizer controls — all live in the single top-bar portal slot.
  // Idle: the trigger icon. Editing: Personal/Default badges to switch which
  // configuration is being edited (active one highlighted), Cancel, and a Save
  // button that targets the active scope ("Save for everyone" for the default).
  const controls = editMode ? (
    <div className="flex items-center gap-x-2">
      <div className="flex items-center gap-x-1">
        <Badge
          size="xsmall"
          color={editScope === "personal" ? "blue" : "grey"}
          className="cursor-pointer"
          onClick={() => switchScope("personal")}
        >
          {t("layout.personalView")}
        </Badge>
        <Badge
          size="xsmall"
          color={editScope === "default" ? "blue" : "grey"}
          className="cursor-pointer"
          onClick={() => switchScope("default")}
        >
          {t("layout.defaultView")}
        </Badge>
      </div>
      <Button
        size="small"
        variant="secondary"
        onClick={cancelEdit}
        disabled={isSaving}
      >
        {t("actions.cancel")}
      </Button>
      <Button
        size="small"
        variant="primary"
        onClick={commitEdit}
        isLoading={isSaving}
      >
        {editScope === "default" && hasChanges
          ? t("layout.saveForEveryone")
          : t("actions.save")}
      </Button>
    </div>
  ) : (
    <Tooltip content={triggerTooltip}>
      <IconButton
        size="small"
        variant="transparent"
        onClick={enterEdit}
        aria-label={t("layout.customizeLayout")}
        className="text-ui-fg-muted hover:text-ui-fg-subtle"
      >
        {/* The "done" icon carries a blue accent dot — reserve it for zones
            that actually have a saved layout, otherwise show the plain icon. */}
        {definedScope ? <AdjustmentsDone /> : <Adjustments />}
      </IconButton>
    </Tooltip>
  )

  const layoutNode = <LayoutComponent sections={renderedSections} data={data} />

  return (
    <>
      {triggerHost ? createPortal(controls, triggerHost) : null}
      {editMode ? (
        <DndContext
          sensors={sensors}
          collisionDetection={collisionDetection}
          onDragStart={handleDragStart}
          onDragOver={handleDragOver}
          onDragEnd={handleDragEnd}
        >
          {layoutNode}
          <DragOverlay>
            {activeEntry ? (
              <div className="bg-ui-bg-base shadow-elevation-flyout ring-ui-border-base min-w-0 rounded-lg ring-1">
                <EntryContent>{activeEntry.render(data)}</EntryContent>
              </div>
            ) : null}
          </DragOverlay>
        </DndContext>
      ) : (
        layoutNode
      )}
      {hasOutlet && <Outlet />}
    </>
  )
}

export const LayoutComposer = Object.assign(LayoutComposerRoot, {
  Entry: LayoutEntry,
})

import { FetchError } from "@medusajs/js-sdk"
import { HttpTypes } from "@medusajs/types"
import { toast } from "@medusajs/ui"
import { MutateOptions } from "@tanstack/react-query"
import { useCallback, useMemo } from "react"
import { useTranslation } from "react-i18next"
import type { LayoutPreference } from "../components/layout-composer/types"
import {
  useLayoutConfiguration,
  useSetLayoutConfiguration,
} from "./api/layouts"

const EMPTY_PREFERENCE: LayoutPreference = { widgets: {} }

export type LayoutScope = "personal" | "default"

export type SetPreferenceOptions = {
  /**
   * Persist as the zone's system default (applies to all users) instead of the
   * current user's personal configuration.
   */
  asDefault?: boolean
}

/**
 * Per-call react-query mutate options for `setPreference`, used to run
 * caller-specific side effects (e.g. exiting edit mode) once the save settles.
 * Generic toasts are already handled inside the hook.
 */
export type SetPreferenceMutateOptions = MutateOptions<
  HttpTypes.AdminLayoutConfigurationResponse,
  FetchError,
  HttpTypes.AdminSetLayoutConfiguration
>

export type UseLayoutPreferenceReturn = {
  /** The current user's personal configuration, seeded from the default when unset. */
  personalPreference: LayoutPreference
  /** The zone's system default configuration. */
  defaultPreference: LayoutPreference
  /** The persisted scope the user is actively viewing for this zone. */
  activeScope: LayoutScope
  /**
   * Which scope actually has a saved configuration for this zone, or `null`
   * when neither the user nor the system has defined one. Personal takes
   * precedence since it overrides the system default for the current user.
   */
  definedScope: LayoutScope | null
  setPreference: (
    next: LayoutPreference,
    options?: SetPreferenceOptions,
    mutateOptions?: SetPreferenceMutateOptions
  ) => void
  isSaving: boolean
}

function toPreference(
  configuration?: { widgets?: LayoutPreference["widgets"] } | null
): LayoutPreference | null {
  const widgets = configuration?.widgets
  return widgets ? { widgets } : null
}

export function useLayoutPreference(zone: string): UseLayoutPreferenceReturn {
  const { t } = useTranslation()

  const { personal_configuration, default_configuration, active_scope } =
    useLayoutConfiguration(zone)

  const { mutate: setLayoutConfiguration, isPending: isSaving } =
    useSetLayoutConfiguration(zone, {
      onSuccess: () => toast.success(t("layout.saveSuccess")),
      onError: (error) => toast.error(error.message),
    })

  const defaultPreference = useMemo(
    () =>
      toPreference(default_configuration?.configuration) ?? EMPTY_PREFERENCE,
    [default_configuration]
  )

  const personalPreference = useMemo(
    () =>
      toPreference(personal_configuration?.configuration) ?? defaultPreference,
    [personal_configuration, defaultPreference]
  )

  const activeScope: LayoutScope = active_scope ?? "personal"

  // A configuration record only exists once a user or admin has saved one, so
  // its presence is the signal that a layout has been deliberately defined.
  // Personal wins over default since it's what the current user actually sees.
  const definedScope: LayoutScope | null = personal_configuration
    ? "personal"
    : default_configuration
    ? "default"
    : null

  const setPreference = useCallback(
    (
      next: LayoutPreference,
      options?: SetPreferenceOptions,
      mutateOptions?: SetPreferenceMutateOptions
    ) => {
      setLayoutConfiguration(
        {
          is_default: options?.asDefault ?? false,
          configuration: { widgets: next.widgets },
        },
        mutateOptions
      )
    },
    [setLayoutConfiguration]
  )

  return {
    personalPreference,
    defaultPreference,
    activeScope,
    definedScope,
    setPreference,
    isSaving,
  }
}

