  @InjectManager()
  @EmitEvents()
  async addProductOptionToProduct(
    data:
      | ProductTypes.ProductOptionProductPair
      | ProductTypes.ProductOptionProductPair[],
    @MedusaContext() sharedContext: Context = {}
  ): Promise<{ id: string } | { id: string }[]> {
    const productOptionProducts = await this.addProductOptionToProduct_(
