import {
  EventBusTypes,
  IEventBusModuleService,
  Message,
  Subscriber,
} from "@medusajs/framework/types"

/**
 * In-memory event bus. Events are dispatched synchronously to the
 * registered subscribers and every emitted message is recorded so tests
 * can assert on the events the module published.
 */
export class FakeEventBus implements IEventBusModuleService {
  protected readonly subscribers_: Map<string | symbol, Set<Subscriber>> =
    new Map()

  emitted: Message[] = []

  async emit<T>(
    messages: Message<T> | Message<T>[],
    options?: Record<string, unknown>
  ): Promise<void> {
    const messages_ = Array.isArray(messages) ? messages : [messages]

    for (const message of messages_) {
      this.emitted.push(message)

      const subscribers = this.subscribers_.get(message.name)

      for (const subscriber of subscribers ?? []) {
        const { options, ...payload } = message
        await subscriber(payload)
      }
    }
  }

  subscribe(event: string | symbol, subscriber: Subscriber): this {
    const subscribers = this.subscribers_.get(event) ?? new Set()
    subscribers.add(subscriber)
    this.subscribers_.set(event, subscribers)
    return this
  }

  unsubscribe(
    event: string | symbol,
    subscriber: Subscriber,
    context?: EventBusTypes.SubscriberContext
  ): this {
    this.subscribers_.get(event)?.delete(subscriber)
    return this
  }

  reset() {
    this.emitted = []
  }

  async releaseGroupedEvents(eventGroupId: string): Promise<void> {}

  async clearGroupedEvents(eventGroupId: string): Promise<void> {}
}

import { ILockingModule } from "@medusajs/framework/types"

/**
 * In-memory locking module. Acquiring a key that is already held throws,
 * which emulates the contention between separate processes the index
 * module guards against (each process would have its own owner id).
 */
export class FakeLocking implements ILockingModule {
  locks: Map<string, string | null> = new Map()

  async execute<T>(
    keys: string | string[],
    job: () => Promise<T>,
    args?: { timeout?: number }
  ): Promise<T> {
    await this.acquire(keys)

    try {
      return await job()
    } finally {
      await this.release(keys)
    }
  }

  async acquire(
    keys: string | string[],
    args?: { ownerId?: string | null; expire?: number }
  ): Promise<void> {
    const keys_ = Array.isArray(keys) ? keys : [keys]

    for (const key of keys_) {
      if (this.locks.has(key)) {
        throw new Error(`Lock for key "${key}" is already acquired`)
      }
    }

    for (const key of keys_) {
      this.locks.set(key, args?.ownerId ?? null)
    }
  }

  async release(
    keys: string | string[],
    args?: { ownerId?: string | null }
  ): Promise<boolean> {
    const keys_ = Array.isArray(keys) ? keys : [keys]

    for (const key of keys_) {
      this.locks.delete(key)
    }

    return true
  }

  async releaseAll(): Promise<void> {
    this.locks.clear()
  }
}

import { Logger } from "@medusajs/framework/types"

/**
 * In-memory logger that records every log entry. Errors are collected
 * separately so the test bed can fail loudly when the module swallows
 * exceptions and only reports them through the logger.
 */
export class FakeLogger {
  logs: { level: string; args: unknown[] }[] = []
  errors: unknown[] = []

  protected record(level: string, args: unknown[]) {
    this.logs.push({ level, args })

    if (level === "error") {
      this.errors.push(args[0])
    }
  }

  info(...args: unknown[]) {
    this.record("info", args)
  }

  warn(...args: unknown[]) {
    this.record("warn", args)
  }

  error(...args: unknown[]) {
    this.record("error", args)
  }

  debug(...args: unknown[]) {
    this.record("debug", args)
  }

  log(...args: unknown[]) {
    this.record("log", args)
  }

  panic(...args: unknown[]) {
    this.record("panic", args)
  }

  failure(...args: unknown[]) {
    this.record("failure", args)
  }

  success(...args: unknown[]) {
    this.record("success", args)
  }

  progress(...args: unknown[]) {
    this.record("progress", args)
  }

  activity(...args: unknown[]) {
    this.record("activity", args)
  }

  shouldLog(): boolean {
    return true
  }

  setLogLevel(): void {}

  unsetLogLevel(): void {}

  asLogger(): Logger {
    return this as unknown as Logger
  }
}

type QueryGraphConfig = {
  entity: string
  fields?: string[]
  filters?: Record<string, any>
  pagination?: {
    order?: Record<string, string>
    take?: number
  }
  withDeleted?: boolean
}

/**
 * In-memory stand-in for the application query graph the index module
 * consumes data from. Tests seed it with records per entity alias and the
 * fake honors the filter/pagination shapes the module relies on:
 *
 * - `filters.id` as an array or single value (event consumption)
 * - `filters.id.$gt` + order/take (data synchronizer cursor pagination)
 *
 * Every call is recorded in `calls` for tests that want to assert how the
 * module queried the data source.
 */
export class FakeQuery {
  protected data: Map<string, Record<string, any>[]> = new Map()

  calls: QueryGraphConfig[] = []

  seed(entity: string, records: Record<string, any>[]) {
    this.data.set(entity, records)
    return this
  }

  reset() {
    this.data.clear()
    this.calls = []
  }

  graph = async (config: QueryGraphConfig): Promise<{ data: any[] }> => {
    this.calls.push(JSON.parse(JSON.stringify(config)))

    let records = [...(this.data.get(config.entity) ?? [])]

    const idFilter = config.filters?.id

    if (Array.isArray(idFilter)) {
      records = records.filter((record) => idFilter.includes(record.id))
    } else if (typeof idFilter === "string") {
      records = records.filter((record) => record.id === idFilter)
    } else if (idFilter && typeof idFilter === "object" && "$gt" in idFilter) {
      records = records.filter((record) => record.id > idFilter.$gt)
    }

    const updatedAtFilter = config.filters?.updated_at
    if (updatedAtFilter?.$gt) {
      records = records.filter(
        (record) =>
          new Date(record.updated_at as string) >
          new Date(updatedAtFilter.$gt as string)
      )
    }

    const idOrder = config.pagination?.order?.id
    if (idOrder) {
      const direction = idOrder.toLowerCase() === "desc" ? -1 : 1
      records.sort((a, b) =>
        a.id === b.id ? 0 : a.id > b.id ? direction : -direction
      )
    }

    if (typeof config.pagination?.take === "number") {
      records = records.slice(0, config.pagination.take)
    }

    return { data: JSON.parse(JSON.stringify(records)) }
  }
}

import { ModuleJoinerConfig } from "@medusajs/framework/types"

